import React, { useState, useEffect } from 'react';
import { Container, Card, Button, Form } from 'react-bootstrap';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';

export default function QuizTake() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [quiz, setQuiz] = useState(null);
  const [answers, setAnswers] = useState({});

  useEffect(() => {
    api.get(`/quizzes/${id}`)
      .then(res => setQuiz(res.data))
      .catch(console.error);
  }, [id]);

  const submit = () => {
    let score = 0;
    quiz.questions.forEach((q, idx) => {
      if (answers[idx] === q.correctIndex) score++;
    });
    navigate('/result', { state: { quiz, answers, score } });
  };

  if (!quiz) return <Container className="fade-in">Loading...</Container>;

  return (
    <Container className="mt-5 fade-in">
      <h2>{quiz.title}</h2>
      {quiz.questions.map((q, idx) => (
        <Card className="mb-3 fade-in" key={idx}>
          <Card.Body>
            <Card.Title>{q.text}</Card.Title>
            <Form>
              {q.options.map((opt, oi) => (
                <Form.Check
                  type="radio"
                  name={`q${idx}`}
                  label={opt}
                  key={oi}
                  checked={answers[idx] === oi}
                  onChange={() => setAnswers({ ...answers, [idx]: oi })}
                />
              ))}
            </Form>
          </Card.Body>
        </Card>
      ))}
      <Button onClick={submit}>Submit Quiz</Button>
    </Container>
  );
}
