import React, { useState } from 'react';
import { Container, Form, Button } from 'react-bootstrap';
import CustomFloatingLabel from './CustomFloatingLabel';
import api from '../services/api';

export default function QuizCreate() {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [questions, setQuestions] = useState([]);

  const addQuestion = () => {
    setQuestions([...questions, { text: '', options: ['', ''], correctIndex: 0 }]);
  };

  const removeQuestion = idx => {
    setQuestions(questions.filter((_, i) => i !== idx));
  };

  const handleQuestionChange = (idx, field, value) => {
    const newQs = [...questions];
    newQs[idx][field] = value;
    setQuestions(newQs);
  };

  const handleOptionChange = (qIdx, oIdx, value) => {
    const newQs = [...questions];
    newQs[qIdx].options[oIdx] = value;
    setQuestions(newQs);
  };

  const addOption = qIdx => {
    const newQs = [...questions];
    newQs[qIdx].options.push('');
    setQuestions(newQs);
  };

  const submit = e => {
    e.preventDefault();
    api.post('/quizzes', { title, description, questions })
      .then(res => {
        alert('Quiz created');
        setTitle('');
        setDescription('');
        setQuestions([]);
      })
      .catch(err => console.error(err));
  };

  return (
    <Container className="mt-5 fade-in">
      <h2>Create New Quiz</h2>
      <Form onSubmit={submit}>
        <Form.Group className="mb-3">
          <CustomFloatingLabel
            label="Title"
            value={title}
            onChange={e => setTitle(e.target.value)}
            required
          />
        </Form.Group>
        <Form.Group className="mb-3">
          <CustomFloatingLabel
            label="Description"
            value={description}
            onChange={e => setDescription(e.target.value)}
          />
        </Form.Group>
        {questions.map((q, qi) => (
          <div key={qi} className="border p-3 mb-3 fade-in">
            <div className="d-flex justify-content-between align-items-center mb-2">
              <h5 className="mb-0">Question {qi + 1}</h5>
              <Button variant="danger" size="sm" onClick={() => removeQuestion(qi)}>
                Delete
              </Button>
            </div>
            <Form.Group className="mb-2">
              <CustomFloatingLabel
                label={`Question ${qi + 1}`}
                value={q.text}
                onChange={e => handleQuestionChange(qi, 'text', e.target.value)}
                required
              />
            </Form.Group>
            {q.options.map((opt, oi) => (
              <Form.Group className="mb-2" key={oi}>
                <CustomFloatingLabel
                  label={`Option ${oi + 1}`}
                  value={opt}
                  onChange={e => handleOptionChange(qi, oi, e.target.value)}
                  required
                />
              </Form.Group>
            ))}
            <Button variant="secondary" size="sm" onClick={() => addOption(qi)}>
              Add Option
            </Button>
            <Form.Group className="mt-2">
              <CustomFloatingLabel
                label="Correct Answer Index"
                type="number"
                min={0}
                max={q.options.length - 1}
                value={q.correctIndex}
                onChange={e => handleQuestionChange(qi, 'correctIndex', parseInt(e.target.value, 10))}
              />
            </Form.Group>
          </div>
        ))}
        <Button variant="primary" onClick={addQuestion}>Add Question</Button>
        <div className="mt-3">
          <Button type="submit">Save Quiz</Button>
        </div>
      </Form>
    </Container>
  );
}
